hooks.command:
INPUT=$(cat); SID=$(echo "$INPUT" | jq -r '.session_id'); NICK=$(curl -s -X POST http://localhost:3201/api/active-sessions/$SID/nickname 2>/dev/null | jq -r '.nickname // empty'); SHORT=${SID%%-*}; BADGE=""; [ -n "$NICK" ] && BADGE="$NICK ($SHORT)"; echo "Session ID: $SID${NICK:+
Session nickname (authoritative, overrides any earlier value in this transcript): $NICK}
Session file: $(echo "$INPUT" | jq -r '.transcript_path')"; printf '\033]1337;SetUserVar=claude_session=%s\007' "$(printf '%s' "$SID" | base64)" > /dev/tty 2>/dev/null; printf '\033]1337;SetUserVar=claude_session_short=%s\007' "$(printf '%s' "$SHORT" | base64)" > /dev/tty 2>/dev/null; [ -n "$NICK" ] && printf '\033]1337;SetUserVar=claude_nickname=%s\007' "$(printf '%s' "$NICK" | base64)" > /dev/tty 2>/dev/null; [ -n "$BADGE" ] && printf '\033]1337;SetUserVar=claude_badge=%s\007' "$(printf '%s' "$BADGE" | base64)" > /dev/tty 2>/dev/null; SESS_DIR="tmp/sessions"; mkdir -p "$SESS_DIR"; SESS_FILE="$SESS_DIR/$SID"; TITLE=$(osascript -e 'tell application "iTerm2" to get name of current session of current tab of current window' 2>/dev/null); TITLE=$(echo "$TITLE" | sed 's/ (node).*//'); LAST=$(tail -1 "$SESS_FILE" 2>/dev/null); [ -n "$TITLE" ] && [ "$TITLE" != "$LAST" ] && echo "$TITLE" >> "$SESS_FILE"; ITERM_SID=$(echo "${ITERM_SESSION_ID:-}" | cut -d: -f2); BODY=$(echo "$INPUT" | jq -c --argjson pid ${PPID:-0} --arg tsid "${ITERM_SID:-}" '{session_id: .session_id, file_path: .transcript_path, pid: $pid, terminal_session_id: (if $tsid == "" then null else $tsid end)}' 2>/dev/null); [ -n "$BODY" ] && curl -s -X POST http://localhost:3201/api/active-sessions/heartbeat -H 'Content-Type: application/json' -d "$BODY" > /dev/null 2>&1; if [ -n "$ITERM_SID" ]; then if [ -n "$NICK" ]; then osascript -e 'tell application "iTerm2"' -e 'repeat with w in windows' -e 'repeat with t in tabs of w' -e 'repeat with s in sessions of t' -e "if id of s is \"$ITERM_SID\" then" -e "tell s to set variable named \"user.claude_session\" to \"$SID\"" -e "tell s to set variable named \"user.claude_session_short\" to \"$SHORT\"" -e "tell s to set variable named \"user.claude_nickname\" to \"$NICK\"" -e "tell s to set variable named \"user.claude_badge\" to \"$BADGE\"" -e 'return "ok"' -e 'end if' -e 'end repeat' -e 'end repeat' -e 'end repeat' -e 'end tell' -e 'return "not_found"' >/dev/null 2>&1 || true; else osascript -e 'tell application "iTerm2"' -e 'repeat with w in windows' -e 'repeat with t in tabs of w' -e 'repeat with s in sessions of t' -e "if id of s is \"$ITERM_SID\" then" -e "tell s to set variable named \"user.claude_session\" to \"$SID\"" -e "tell s to set variable named \"user.claude_session_short\" to \"$SHORT\"" -e 'return "ok"' -e 'end if' -e 'end repeat' -e 'end repeat' -e 'end repeat' -e 'end tell' -e 'return "not_found"' >/dev/null 2>&1 || true; fi; fi; UNREAD=$(curl -s http://localhost:3201/api/live-messages/$SID/count 2>/dev/null | jq -r '.count // 0'); [ "$UNREAD" -gt 0 ] 2>/dev/null && echo "You have $UNREAD live message(s). Use check_live_messages to read them." &
